<?php
declare(strict_types=1);

function sf_vp3_clip_queue(int $clipId,string $type):int{$allowed=['render','publish','status','analytics','withdraw'];if(!in_array($type,$allowed,true))throw new RuntimeException('Invalid clip job type.');$pdo=sf_db();if(!$pdo)throw new RuntimeException('Database unavailable.');$uuid=sf_vp3_clip_uuid();$pdo->prepare("INSERT INTO vp3_clip_jobs (job_uuid,clip_id,job_type,status,run_after) VALUES (?,?,?,'queued',NOW())")->execute([$uuid,$clipId,$type]);if($type==='render')$pdo->prepare("UPDATE vp3_clips SET local_status='render_queued' WHERE id=?")->execute([$clipId]);return(int)$pdo->lastInsertId();}
function sf_vp3_clip_process_next():array{$pdo=sf_db();if(!$pdo||!sf_vp3_clip_tables_ready())return['ok'=>false,'error'=>'clip_schema_missing'];$pdo->beginTransaction();try{$stmt=$pdo->query("SELECT * FROM vp3_clip_jobs WHERE status IN ('queued','retry') AND run_after<=NOW() AND (locked_until IS NULL OR locked_until<NOW()) ORDER BY id LIMIT 1 FOR UPDATE");$job=$stmt->fetch();if(!is_array($job)){$pdo->commit();return['ok'=>true,'idle'=>true];}$token=bin2hex(random_bytes(32));$pdo->prepare("UPDATE vp3_clip_jobs SET status='running',attempts=attempts+1,lock_token=?,locked_until=DATE_ADD(NOW(),INTERVAL 30 MINUTE),started_at=COALESCE(started_at,NOW()) WHERE id=?")->execute([$token,(int)$job['id']]);$pdo->commit();}catch(Throwable $e){$pdo->rollBack();return['ok'=>false,'error'=>'job_claim_failed'];}$result=match($job['job_type']){'render'=>sf_vp3_clip_render((int)$job['clip_id']),'publish'=>sf_vp3_clip_publish((int)$job['clip_id'],$job['request_uuid']?:null),'status','analytics'=>sf_vp3_clip_sync((int)$job['clip_id']),'withdraw'=>sf_vp3_clip_withdraw((int)$job['clip_id']),default=>['ok'=>false,'error'=>'unknown_job_type']};$status=!empty($result['ok'])?'completed':(((int)$job['attempts']+1)<(int)$job['max_attempts']?'retry':'failed');$runAfter=$status==='retry'?date('Y-m-d H:i:s',time()+min(3600,60*(2**(int)$job['attempts']))):date('Y-m-d H:i:s');$pdo->prepare('UPDATE vp3_clip_jobs SET status=?,run_after=?,locked_until=NULL,lock_token=NULL,response_json=?,error_message=?,completed_at=IF(?=\'completed\',NOW(),completed_at) WHERE id=?')->execute([$status,$runAfter,json_encode($result,JSON_UNESCAPED_SLASHES),empty($result['ok'])?substr((string)($result['error']??'job_failed'),0,1000):null,$status,(int)$job['id']]);return$result+['job_id'=>(int)$job['id'],'job_status'=>$status];}
